mapper.update:
UPDATE CHAT_ROOM_MEMBER
SET LAST_READ_MESSAGE_ID = #{messageId}
WHERE ROOM_ID = #{roomId} AND EMPLOYEE_ID = #{employeeId}

mapper.select:
SELECT m.MESSAGE_ID AS messageId, m.ROOM_ID AS roomId, m.SENDER_ID AS senderId, e.EMPLOYEE_NAME AS senderName, p.POSITION_NAME AS senderPositionName, m.MESSAGE_TYPE AS messageType, m.CONTENT AS content, a.FILE_NAME AS fileName, a.FILE_PATH AS filePath, a.FILE_SIZE AS fileSize, m.SENT_AT AS sentAt FROM CHAT_MESSAGE m LEFT JOIN EMPLOYEE e ON e.EMPLOYEE_ID = m.SENDER_ID LEFT JOIN POSITION p ON p.POSITION_ID = e.POSITION_ID LEFT JOIN CHAT_ATTACHMENT a ON a.MESSAGE_ID = m.MESSAGE_ID WHERE m.ROOM_ID = #{roomId}
AND m.MESSAGE_ID < #{beforeMessageId}
ORDER BY m.MESSAGE_ID DESC LIMIT #{size}
